var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"이면세계 가변 심도 좌표\\n<color=#ff3636>필하모닉 홀</color>","JPN":"裏世界可変深度座標\\n<color=#ff3636>フィルハーモニーホール</color>","ENG":"[[","TWN":"異界可變深度座標\\n<color=#ff3636>管弦樂廳</color>","SCN":"异界可变深度坐标\\n<color=#ff3636>交响乐厅</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 야크샤 전대, 카르데나스 전대.\\n강습 작전 수행 중.\\n작전명 <color=#ffd34c>트러블 슈팅</color>","JPN":"管理局ヤクシャー戦隊、カルデナス戦隊。\\n強襲作戦遂行中。\\n作戦名<color=#ffd34c>トラブルシューティング</color>","ENG":"[[","TWN":"舊管理局 夜叉戰隊、卡特納斯戰隊\\n執行強襲作戰中。\\n作戰名稱 <color=#ffd34c>故障排除</color>","SCN":"管理局夜叉战队、卡尔德纳斯战队。\\n正在执行强袭作战。\\n作战代号<color=#ffd34c>故障排除</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"싫어……! 내 머릿속을 헤집지 마!! 싫어어어어!!","JPN":"嫌だ……！　頭ん中を掻きまわすな！！　止めろぉぉぉ！！","ENG":"No...! Get out of my head!! Stop!!","TWN":"走開……！滾出我的腦袋！！討厭！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"멈춰!! 아군이다! 능력을 사용하지 마!","JPN":"止めろ！！　味方だ！　能力を使うな！","ENG":"Stop!! We’re allies! Don’t use your powers!","TWN":"住手！！是我方人員！不要使用能力！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"틀렸습니다! 이미 제정신이 아니에요! 사살해야 합니다!!","JPN":"だめです！　正気を失っています！　殺さなければ！！","ENG":"Too late! He’s already lost his mind! We must shoot!","TWN":"不行！他現在已經神智不清！必須立刻擊斃！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"내 배 안에 벌레가 들어 있어…… 내, 내 배 안에서 그게 꿈틀거리다가……!","JPN":"腹の中に虫が入っている……ぼ、僕の腹の中であれがうごめいて……！","ENG":"There’s a bug in my stomach... It’s, it’s wiggling around in my stomach...!","TWN":"我肚子裡有蟲……蟲在我的肚子裡蠕動……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"정신 차려, 이 멍청아! 그건 놈들이 덮어 씌운 기억이야! 속지 마!!","JPN":"しっかりしろ、バカ野郎！　それはやつらが上書きした記憶だ！　騙されるな！！","ENG":"Pull yourself together, idiot! That’s just a memory they’ve planted into your brain! Don’t be fooled!","TWN":"傻瓜，你清醒一點！這是那些傢伙植入的記憶！不可以上當！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"어서 진정제 주사해! 저 놈 자기 손으로 배 가르는 꼴 보고 싶어?!","JPN":"早く鎮静剤を打て！　あいつが自分の腹を切るところが見たいのか！？","ENG":"Somebody, sedate him! Do you want to see him rip his stomach apart with his own hands?!","TWN":"立刻給他打鎮定劑！還是你想看他把自己的肚皮挖破？！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지휘부에! 멘탈 프린팅을 촉발하는 파동이 검출되었습니다!</color>","JPN":"<color=#ffd34c>司令部へ！　メンタル・プリンティングを起こす波動が検出されました！</color>","ENG":"<color=#ffd34c>Headquarters! A wave triggering Mental Printing has been detected!</color>","TWN":"<color=#ffd34c>指揮部感應到觸發智力複印的波動！</color>"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>첩보가 틀렸습니다! 마에스트로가 아직 이곳에……!</color>","JPN":"<color=#ffd34c>諜報が間違っていました！　マエストロがまだここに……！</color>","ENG":"<color=#ffd34c>Our intel was wrong! Maestra is still here...!</color>","TWN":"<color=#ffd34c>情報有誤！指揮家尚未……！</color>"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국 놈들은 모두 죽여버려! 안돼, 쏘지 마! 죽여 버려! 함장님! 사, 살려……!","JPN":"管理局のやつらは全員死んじまえ！　止めろ、撃つな！　殺せ！　艦長！　た、助け……！","ENG":"Kill everyone from the Administration! Wait, don’t shoot! DIE! Leader! Sa-Save M...!","TWN":"把管理局的傢伙全都殺光！不可以，別開槍！殺光！艦長！救我……！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이런 말도 안 되는 일이……!","JPN":"そんな馬鹿な……こんなことに！","ENG":"Impossible...!","TWN":"該死……！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 제9 포격전대 <color=#ffd34c>메이즈</color>\\n전대장 류드밀라","JPN":"管理局第9砲撃戦隊<color=#ffd34c>メイズ</color>\\n戦隊長リュドミラ","ENG":"[[","TWN":"管理局第9炮擊戰隊<color=#ffd34c>梅茲</color>\\n戰隊長盧德米拉","SCN":"管理局第9炮击战队<color=#ffd34c>梅兹</color>\\n战队长卢德米拉","DEU":"[[","FRA":"[["},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"모네카! 뭔가 대책이 없나!","JPN":"モネカ！　何か対策はないのか！","ENG":"Moneka! Is there anything we can do?!","TWN":"莫奈卡！有什麼對策嗎！？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"연합전대가 이렇게 허무하게 당하고 있는 꼴을 지켜만 볼 수는 없단 말이다!","JPN":"連合戦隊がこんなにあっけなくやられているところを見過ごすわけにはいかないだろう！","ENG":"We can't stand by and watch the coalition divisions suffer in vain!","TWN":"我們不能就這樣眼睜睜地看著聯合戰隊白白犧牲！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"진정하세요, 메이즈 전대장님!","JPN":"落ち着いてください、メイズ戦隊長！","ENG":"Calm down, Maze Division Commander!","TWN":"請冷靜，梅茲戰隊長！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 전대급 전술지원 <color=#ffd34c>AI</color>\\n모네카","JPN":"管理局戦隊級戦術支援<color=#ffd34c>AI</color>\\nモネカ","ENG":"[[","TWN":"管理局戰隊戰術支援<color=#ffd34c>AI</color>\\n莫奈卡","SCN":"管理局战队级战术支援<color=#ffd34c>AI</color>\\n莫妮卡","DEU":"[[","FRA":"[["},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"진정하라고? 전우들의 비명을 듣고 있는데 어떻게 진정할 수 있지!?","JPN":"落ち着けだと？　戦友たちの悲鳴を聞いて落ち着くことなどできるはずないだろう！","ENG":"Calm down?! How can I be calm when I hear the screams of our comrades?!","TWN":"冷靜？聽著戰友們的慘叫聲，你讓我怎麼冷靜？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이런 탁상공론을 하는 동안에도 전우들의 목숨은 희생되고 있다!","JPN":"こうしている間にも戦友たちの命が犠牲になっているんだ！","ENG":"While we're here discussing unimportant things, the lives of our comrades are being sacrificed!","TWN":"就在我們紙上談兵的時候，犧牲的戰友越來越多了！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"급한 마음은 이해하지만, 지금은 연합전대를 구하러 갈 수 있는 상황이 아니에요!","JPN":"お気持ちはわかりますが、今は連合戦隊を助けに行ける状況ではありません！","ENG":"I understand your frustration, but now is not the time to go rescue our coalition divisions!","TWN":"我理解你焦急的心情，但現在的情況，不適合去救援聯合戰隊！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"관리국은 현재 대기권 너머의 궤도병기로부터 폭격을 당하고 있습니다.","JPN":"現在、管理局は大気圏の外にある軌道兵器から砲撃を受けています。","ENG":"The Administration is currently under orbital bombardment from beyond the atmosphere.","TWN":"管理局目前正在遭受大氣層外軌道武器的轟炸。"},"stage":{"bg":"MS_1204_01","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};